/// <summary>
/// Determines if concurrent deletes should throw exception.
/// </summary>
/// <returns>true, if exception should be thrown; otherwise, false.</returns>
public boolean shouldThrowExceptionOnZeroDelete()
{
    return true;
}

public static void populate()
{

    LicensingEntitlementObjects                 licensingEntitlementObjects;
    LicensingAllEntitledPermissions             licensingAllEntitledPermissions;
    LicensingAllSkus                            licensingAllSkus;
    LicensingElementsRequiringEntitlement       licensingElementsRequiringEntitlement;

    // Target table (as requested)
    DEVLicenseReportObjectLicences              licenseReportObjectLicences;

    // entitlementObjectRecId -> best SkuName (by Priority, then SkuName)
    Map readSkuNameByEntitlementObject  = new Map(Types::Int64, Types::String);
    Map writeSkuNameByEntitlementObject = new Map(Types::Int64, Types::String);

    RecordInsertList recordInsertList = new RecordInsertList(tableNum(DEVLicenseReportObjectLicences));

    // Optional: clear target first
    ttsbegin;
    delete_from licenseReportObjectLicences;
    ttscommit;

    // -------------------------
    // STEP 1: Best READ SKU per EntitlementObject
    // AccessLevel IN (1,2)
    // ORDER BY EntitlementObject, Priority, SkuName
    // First row per EntitlementObject wins.
    // -------------------------
    while select licensingAllEntitledPermissions
        order by licensingAllEntitledPermissions.EntitlementObject,
                    licensingAllSkus.Priority,
                    licensingAllSkus.SkuName
        where licensingAllEntitledPermissions.AccessLevel == 1
            || licensingAllEntitledPermissions.AccessLevel == 2
        join licensingAllSkus
            where licensingAllSkus.RecId == licensingAllEntitledPermissions.SkuRecId
    {
        if (!readSkuNameByEntitlementObject.exists(licensingAllEntitledPermissions.EntitlementObject))
        {
            readSkuNameByEntitlementObject.insert(licensingAllEntitledPermissions.EntitlementObject, licensingAllSkus.SkuName);
        }
    }

    // -------------------------
    // STEP 2: Best WRITE SKU per EntitlementObject
    // AccessLevel = 2
    // ORDER BY EntitlementObject, Priority, SkuName
    // First row per EntitlementObject wins.
    // -------------------------
    while select licensingAllEntitledPermissions
        order by licensingAllEntitledPermissions.EntitlementObject,
                licensingAllSkus.Priority,
                licensingAllSkus.SkuName
        where licensingAllEntitledPermissions.AccessLevel == 2
    join licensingAllSkus
        where licensingAllSkus.RecId == licensingAllEntitledPermissions.SkuRecId
    {
        if (!writeSkuNameByEntitlementObject.exists(licensingAllEntitledPermissions.EntitlementObject))
        {
            writeSkuNameByEntitlementObject.insert(licensingAllEntitledPermissions.EntitlementObject, licensingAllSkus.SkuName);
        }
    }

    // -------------------------
    // STEP 3: Insert required entitlement objects (EXISTS) into DEV table
    // ORDER BY AotName, SecurableType
    // Bulk insert via RecordInsertList
    // -------------------------
    ttsbegin;

    while select licensingEntitlementObjects
        order by licensingEntitlementObjects.AotName,
                licensingEntitlementObjects.SecurableType
        exists join licensingElementsRequiringEntitlement
            where licensingElementsRequiringEntitlement.EntitlementObject == licensingEntitlementObjects.RecId
    {
        licenseReportObjectLicences.clear();

        // NOTE: Adjust field names on DEVLicenseReportObjectLicences if they differ.
        licenseReportObjectLicences.EntitlementObject = licensingEntitlementObjects.RecId;
        licenseReportObjectLicences.AotName           = licensingEntitlementObjects.AotName;
        licenseReportObjectLicences.SecurableType     = licensingEntitlementObjects.SecurableType;

        if (readSkuNameByEntitlementObject.exists(licensingEntitlementObjects.RecId))
        {
            licenseReportObjectLicences.ReadLicense = readSkuNameByEntitlementObject.lookup(licensingEntitlementObjects.RecId);
        }
        else
        {
            licenseReportObjectLicences.ReadLicense = ''; // or leave default if nullable
        }

        if (writeSkuNameByEntitlementObject.exists(licensingEntitlementObjects.RecId))
        {
            licenseReportObjectLicences.WriteLicense = writeSkuNameByEntitlementObject.lookup(licensingEntitlementObjects.RecId);
        }
        else
        {
            licenseReportObjectLicences.WriteLicense = '';
        }

        recordInsertList.add(licenseReportObjectLicences);
    }

    recordInsertList.insertDatabase();

    ttscommit;
}
